import{_ as t,o as s,c as o,a2 as b}from"./chunks/framework.Nkqvsbxc.js";const d=JSON.parse('{"title":"蒙山施食儀","description":"","frontmatter":{},"headers":[],"relativePath":"scriptures/蒙山施食仪.md","filePath":"scriptures/蒙山施食仪.md"}'),n={name:"scriptures/蒙山施食仪.md"};function p(g,r,e,a,_,c){return s(),o("div",null,[...r[0]||(r[0]=[b('<h1 id="蒙山施食儀" tabindex="-1">蒙山施食儀 <a class="header-anchor" href="#蒙山施食儀" aria-label="Permalink to &quot;蒙山施食儀&quot;">​</a></h1><p>（念誦前應備淨水淨飯等）</p><p>一、華嚴經偈頌（三遍）<br> 若人欲了知，三世一切佛，應觀法界性，一切唯心造。<br></p><p>二、破地獄眞言（三遍） 唵。伽羅帝耶娑婆訶。<br></p><p>三、普召請眞言（三遍）<br> 南無部部帝唎。伽哩哆哩怛哆誐哆耶。<br></p><p>四、解冤結眞言（三遍）<br> 唵。三陀羅伽陀娑婆訶。<br></p><p>五、迎請三寶<br> 南無大方廣佛華嚴經<br> 南無常住十方佛<br> 南無常住十方法<br> 南無常住十方僧<br> 南無本師釋迦牟尼佛<br> 南無大悲觀世音菩薩<br> 南無冥陽救苦地藏王菩薩<br> 南無啟教阿難陀尊者<br></p><p>六、秉受三皈（三遍）<br> 皈依佛，皈依法，皈依僧<br> 皈依佛，兩足尊；皈依法，離欲尊；皈依僧，眾中尊。<br> 皈依佛竟，皈依法竟，皈依僧竟。<br></p><p>七、懺悔三業<br><strong>佛子</strong>所造諸惡業，皆由無始貪瞋癡，從身語意之所生，一切<strong>佛子</strong>皆懺悔。<br><strong>有情</strong>所造諸惡業，皆由無始貪瞋癡，從身語意之所生，一切<strong>有情</strong>皆懺悔。<br><strong>孤魂</strong>所造諸惡業，皆由無始貪瞋癡，從身語意之所生，一切<strong>孤魂</strong>皆懺悔。<br></p><p>八、發願<br> 眾生無邊誓願度，煩惱無盡誓願斷，法門無量誓願學，佛道無上誓願成。（三遍）<br> 自性眾生誓願度，自性煩惱誓願斷，自性法門誓願學，自性佛道誓願成。（三遍）<br></p><p>九、滅定業眞言 <br> 唵。鉢羅末隣陀寧娑婆訶。 （三遍）<br></p><p>十、滅業障眞言<br> 唵。阿嚕勒繼娑婆訶。 （三遍）<br></p><p>十一、開咽喉眞言<br> 唵。步步底哩伽哆哩。怛哆誐哆耶。 （三遍） <br></p><p>十二、三昧耶戒眞言<br> 唵。三昧耶。薩埵錽。 （三遍）<br></p><p>十三、變食眞言<br> 南無薩縛怛他誐哆。縛嚕枳帝唵。三跋羅。三跋羅吽。（三遍）<br></p><p>十四、甘露水眞言<br> 南無蘇嚕婆耶。怛他誐哆耶。怛姪他唵。蘇嚕蘇嚕。鉢羅蘇嚕。鉢羅蘇嚕。娑婆訶。（三遍）<br></p><p>十五、一字水輪眞言<br> 唵。錽錽錽錽錽。（三遍）<br></p><p>十六、乳海眞言<br> 南無三滿哆。沒馱喃。唵。錽。（三遍）<br></p><p>十七、七寶如來名（三遍）<br> 南無多寶如來 <br> 南無寶勝如來 <br> 南無妙色身如來 <br> 南無廣博身如來 <br> 南無離怖畏如來 <br> 南無甘露王如來<br><br> 南無阿彌陀如來<br></p><p>十八、結願<br> 神咒加持<strong>淨法食</strong>，普施河沙眾<strong>佛子</strong>，願皆飽滿捨慳貪，速脫幽冥生淨土，皈依三寶發菩提，究竟得成無上道，功德無邊盡未來，一切<strong>佛子</strong>同法食。<br> 神咒加持<strong>法施食</strong>，普施河沙眾<strong>有情</strong>，願皆飽滿捨慳貪，速脫幽冥生淨土，皈依三寶發菩提，究竟得成無上道，功德無邊盡未來，一切<strong>有情</strong>同法食。<br> 神咒加持<strong>甘露水</strong>，普施河沙眾<strong>孤魂</strong>，願皆飽滿捨慳貪，速脫幽冥生淨土，皈依三寶發菩提，究竟得成無上道，功德無邊盡未來，一切<strong>孤魂</strong>同法食。<br></p><p>十九、正施<br> 汝等<strong>佛子</strong>眾，我今施汝，供汝，此食徧十方，一切<strong>佛子</strong>共。願以此功德，普及於一切，施食與<strong>佛子</strong>，皆共成佛道。<br> 汝等<strong>有情</strong>眾，我今施汝，供汝，此食徧十方，一切<strong>有情</strong>共。願以此功德，普及於一切，施食與<strong>有情</strong>，皆共成佛道。<br> 汝等<strong>孤魂</strong>眾，我今施汝，供汝，此食徧十方，一切<strong>孤魂</strong>共。願以此功德，普及於一切，施食與<strong>孤魂</strong>，皆共成佛道。<br></p><p>二十、施無遮食眞言<br> 唵。穆力陵。娑婆訶。 （三遍） <br></p><p>二十一、普供養眞言<br> 唵。誐誐曩。三婆縛。伐日羅斛。 （三遍） <br></p><p>二十二、般若波羅蜜多心經<br> 觀自在菩薩。行深般若波羅蜜多時。照見五蘊皆空。度一切苦厄。舍利子。色不異空。空不異色。色即是空。空即是色。受想行識。亦復如是。舍利子。是諸法空相。不生不滅。不垢不淨。不增不減。是故空中無色。無受想行識。無眼耳鼻舌身意。無色聲香味觸法。無眼界。乃至無意識界。無無明。亦無無明盡。乃至無老死。亦無老死盡。無苦集滅道。無智亦無得。以無所得故。菩提薩埵。依般若波羅蜜多故。心無罣礙。無罣礙故。無有恐怖。遠離顛倒夢想。究竟涅槃。三世諸佛。依般若波羅蜜多故。得阿耨多羅三藐三菩提。故知般若波羅蜜多。是大神咒。是大明咒。是無上咒。是無等等咒。能除一切苦。真實不虛。故說般若波羅蜜多咒。即說咒曰。揭諦揭諦。波羅揭諦。波羅僧揭諦。菩提薩婆訶。<br></p>',24)])])}const l=t(n,[["render",p]]);export{d as __pageData,l as default};
